<template>
    <div class="EchartsTry2">
        <div id="main2" style="width: 300px;height:200px;"></div>
    </div>
</template>
  
<script>
import * as echarts from 'echarts'
export default {
    name: 'EchartsTry2',
    methods: {
        myEcharts() {
            // 基于准备好的dom，初始化echarts实例
            var myChart = echarts.init(document.getElementById('main2'));

            var xAxisData = [];
            var data1 = [];
            var data2 = [];
            for (var i = 0; i < 100; i++) {
                xAxisData.push('A' + i);
                data1.push((Math.sin(i / 5) * (i / 5 - 10) + i / 6) * 5);
                data2.push((Math.cos(i / 5) * (i / 5 - 10) + i / 6) * 5);
            }


            let option = {
                title: {
                    text: 'Chart2'
                },
                legend: {
                    data: ['bar', 'bar2']
                },
                toolbox: {
                    // y: 'bottom',
                    feature: {
                        magicType: {
                            type: ['stack']
                        },
                        dataView: {},
                        saveAsImage: {
                            pixelRatio: 2
                        }
                    }
                },
                tooltip: {},
                xAxis: {
                    data: xAxisData,
                    splitLine: {
                        show: false
                    }
                },
                yAxis: {},
                series: [
                    {
                        name: 'bar',
                        type: 'bar',
                        data: data1,
                        emphasis: {
                            focus: 'series'
                        },
                        animationDelay: function (idx) {
                            return idx * 10;
                        }
                    },
                    {
                        name: 'bar2',
                        type: 'bar',
                        data: data2,
                        emphasis: {
                            focus: 'series'
                        },
                        animationDelay: function (idx) {
                            return idx * 10 + 100;
                        }
                    }
                ],
                animationEasing: 'elasticOut',
                animationDelayUpdate: function (idx) {
                    return idx * 5;
                }
            };

            // 使用刚指定的配置项和数据显示图表。
            myChart.setOption(option);
        }
    },
    mounted() {
        console.log('Mounted2 called');
        this.myEcharts();
        console.log('Mounted2 called successful');
    }
}
</script>
  
