<template>
    <div id="container">

    </div>
   
  </template>
  
  <script>
  import AMapLoader from '@amap/amap-jsapi-loader'
      window._AMapSecurityConfig = {
            securityJsCode: '71907b18a9659bc8023fad8d89e9cdeb'
      }
      
  export default {
    data() {
      return {
        map: null
      }
    },
    methods: {
      initMap() {
        AMapLoader.load({
          key: '7070d3ef1489325fa00869aab7a42162', // 申请好的Web端开发者Key，首次调用 load 时必填
          version: '2.0', // 指定要加载的 JSAPI 的版本，缺省时默认为 1.4.15
          plugins: [''] // 需要使用的的插件列表，如比例尺'AMap.Scale'等
        })
          .then(AMap => {
            this.map = new AMap.Map('container', {
              //设置地图容器id
              // viewMode: '3D', //是否为3D地图模式
              layers: [// 卫星
                      new AMap.TileLayer.Satellite(),
                      // 路网
                      new AMap.TileLayer.RoadNet()],
              zoom: 13, //初始化地图级别
              center: [121.539788, 31.580216] //初始化地图中心点位置
            })
            
          })
          .catch(e => {
            console.log(e)
          })
      }
    },
    mounted() {
      //DOM初始化完成进行地图初始化
      this.initMap()
      console.log('地图初始化完成')
    }
  }
  </script>
  
  <style lang="less">
  #container {
    padding: 0px;
    margin: 0px;
    width: 100%;
    height: 100%;
  }
  </style>
  
  