<template>
    <div class="EchartsTry6">
        <div id="main6" style="width: 300px;height:200px;"></div>
    </div>
</template>
  
<script>
import * as echarts from 'echarts'
export default {
    name: 'EchartsTry6',
    methods: {
        myEcharts() {
            // 基于准备好的dom，初始化echarts实例
            var myChart = echarts.init(document.getElementById('main6'));
            let option = {
  xAxis: {
    type: 'category',
    boundaryGap: false
  },
  yAxis: {
    type: 'value',
    boundaryGap: [0, '30%']
  },
  visualMap: {
    type: 'piecewise',
    show: false,
    dimension: 0,
    seriesIndex: 0,
    pieces: [
      {
        gt: 1,
        lt: 3,
        color: 'rgba(0, 0, 180, 0.4)'
      },
      {
        gt: 5,
        lt: 7,
        color: 'rgba(0, 0, 180, 0.4)'
      }
    ]
  },
  series: [
    {
      type: 'line',
      smooth: 0.6,
      symbol: 'none',
      lineStyle: {
        color: '#5470C6',
        width: 5
      },
      markLine: {
        symbol: ['none', 'none'],
        label: { show: false },
        data: [{ xAxis: 1 }, { xAxis: 3 }, { xAxis: 5 }, { xAxis: 7 }]
      },
      areaStyle: {},
      data: [
        ['2023-10-10', 200],
        ['2023-10-11', 560],
        ['2023-10-12', 750],
        ['2023-10-13', 580],
        ['2023-10-14', 250],
        ['2023-10-15', 300],
        ['2023-10-16', 450],
        ['2023-10-17', 300],
        ['2023-10-18', 100]
      ]
    }
  ]
};

            // 使用刚指定的配置项和数据显示图表。
            myChart.setOption(option);
        }
    },
    mounted() {
        console.log('Mounted6 called');
        this.myEcharts();
        console.log('Mounted6 called successful');
    }
}
</script>
  
