<template>
    <div class="EchartsTry3">
        <div id="main3" style="width: 300px;height:200px;"></div>
    </div>
</template>
  
<script>
import * as echarts from 'echarts'
export default {
    name: 'EchartsTry3',
    methods: {
        myEcharts() {
            // 基于准备好的dom，初始化echarts实例
            var myChart = echarts.init(document.getElementById('main3'));
            let option = {
  xAxis: {
    type: 'category',
    boundaryGap: false,
    data: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun']
  },
  yAxis: {
    type: 'value'
  },
  series: [
    {
      data: [820, 932, 901, 934, 1290, 1330, 1320],
      type: 'line',
      areaStyle: {}
    }
  ]
};

            // 使用刚指定的配置项和数据显示图表。
            myChart.setOption(option);
        }
    },
    mounted() {
        console.log('Mounted3 called');
        this.myEcharts();
        console.log('Mounted3 called successful');
    }
}
</script>
  
